#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read(int *s)
{
	char ch=getchar();int p=0;while(ch<'a'||ch>'z')ch=getchar();
	while(ch<='z'&&ch>='a')s[++p]=ch-'a',ch=getchar();return p;
}
const int N=1e5+10;int top,a[N],n,dp[N][26],stk[N];char t[N];
int main()
{
	n=read(a);rep(1,n,i)
	{
		if(dp[i-1][a[i]])rep(0,25,j)dp[i][j]=dp[dp[i-1][a[i]]-1][j];
		if(top&&stk[top]==a[i])--top;else stk[++top]=a[i];dp[i][a[i]]=i;
	}
	if(top){puts("-1");return 0;} stk[top=1]=n+1;
	rep(1,n,i)
	{
		if(top&&i==stk[top])putchar(')'),--top;
		else putchar('('),stk[top+1]=dp[stk[top]-1][a[i]],++top;
	}
}
